import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "auto-mootori-korrosioon";
const META_TITLE = "Auto mootori korrosioon – kuidas see tekib ja kuidas seda vältida?";
const META_DESCRIPTION =
  "Selgitame, kuidas tekib mootori korrosioon vanematel autodel ja kuidas seda ennetada õige õli, jahutusvedeliku ja sõiduharjumustega.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootori korrosioon, niiskus, jahutusvedelik",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogAutoMootoriKorrosioon() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-auto-mootori-korrosioon",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Auto mootori korrosioon – kuidas see tekib ja kuidas seda vältida?</Heading>

          <p>
            Korrosioon ei tähenda ainult roostes karpe ja põhja. Ka <strong>mootori sees</strong> käib vaikselt söövitustöö,
            eriti vanematel autodel, mida kasutatakse palju lühikestel distantsidel ja mille vedelikke ei vahetata õigeaegselt.
          </p>

          <Heading as="h2">Kust tuleb niiskus mootorisse?</Heading>
          <p>
            Iga külmkäivituse ja lühikese sõidu järel jääb mootorisse <strong>kondensatsioon</strong>. Kui mootor ei jõua
            töötemperatuurini, ei aurustu see niiskus ära ning moodustab koos põlemisjääkide ja happeliste ühenditega agressiivse
            segu, mis ründab metallpindu.
          </p>

          <Heading as="h2">Õli roll korrosiooni ennetamisel</Heading>
          <p>
            Mootoriõlis on <strong>korrosioonivastased lisandid</strong>, mis neutraliseerivad happeid ja loovad kaitsekihi
            metallpindadele. Kui õli on vana, on lisandipakett ammendunud ja õli muutub ise söövitavaks. Seetõttu on regulaarsel
            õlivahetusel otsene mõju korrosioonikaitsele.
          </p>

          <Heading as="h2">Jahutusvedelik – tihti ignoreeritud risk</Heading>
          <p>
            Vana jahutusvedelik kaotab korrosioonikaitse. PH tase muutub, tekib sade, mis ründab <strong>plokki, plokikaant,
            radiaatorit ja veepumpa</strong>. Vanematel autodel, kus vedelikku pole aastaid vahetatud, on korrosioon enamasti
            süsteemne, mitte lokaalne probleem.
          </p>

          <Heading as="h2">Lühikesed sõidud – korrosiooni lemmikstsenaarium</Heading>
          <p>
            Kui sõiduprofiil on stiilis „5 km poodi ja tagasi“, ei jõua mootor kunagi ideaalsesse töörežiimi. Niiskus ja
            kütusejäägid kogunevad õlisse ning <strong>mootori sisemus ei kuiva</strong> ära. Lahendus: kasuta aeg-ajalt pikemaid
            sõite ja lühenda õli- ning jahutusvedeliku vahetusintervalle.
          </p>

          <Heading as="h2">Mootori seismine – eriti riskantne vanadel autodel</Heading>
          <p>
            Kui auto seisab kuude kaupa, tekib korrosioon <strong>kolvidel, silindriseintel ja klappidel</strong>. Seismise eel tasub
            teha õlivahetus, hoida paak pigem täis (vähem kondentsi) ja võimalusel käivitada mootorit aeg-ajalt ning lasta tal soojaks minna.
          </p>

          <Heading as="h2">Kokkuvõte: korrosioon on vaikne kulutaja</Heading>
          <p>
            <strong>Mootori korrosioon vanematel autodel</strong> ei anna end kohe tunda, aga lühendab oluliselt jõuallika eluiga.
            Õige õli, värske jahutusvedelik ja mõistlik sõiduprofiil on kolm lihtsat hooba, millega saad kahju oluliselt vähendada.
          </p>
        </article>
      </main>
    </div>
  );
}

