import React from "react";
import { CheckCircle2, AlertCircle, Info, Lightbulb, Wrench } from "lucide-react";

// Enhanced Components for Blog Posts

export const Paragraph = ({ children }) => (
  <p
    style={{
      fontSize: "1.125rem",
      lineHeight: 1.8,
      marginBottom: "1.5rem",
      color: "#d0d0d5",
      fontWeight: 400,
      letterSpacing: "0.01em",
    }}
  >
    {children}
  </p>
);

export const Strong = ({ children }) => (
  <strong
    style={{
      color: "#48C9B0",
      fontWeight: 700,
      textShadow: "0 0 20px rgba(72, 201, 176, 0.2)",
    }}
  >
    {children}
  </strong>
);

export const List = ({ children, ordered = false }) => {
  const Tag = ordered ? "ol" : "ul";
  return (
    <Tag
      style={{
        paddingLeft: "1.5rem",
        marginTop: "1rem",
        marginBottom: "2rem",
        listStyleType: "none",
      }}
    >
      {children}
    </Tag>
  );
};

export const ListItem = ({ children, icon }) => (
  <li
    style={{
      marginBottom: "0.75rem",
      paddingLeft: "2rem",
      position: "relative",
      color: "#d0d0d5",
      fontSize: "1.1rem",
      lineHeight: 1.7,
    }}
  >
    <span
      style={{
        position: "absolute",
        left: 0,
        top: "0.2rem",
        color: "#48C9B0",
      }}
    >
      {icon || <CheckCircle2 size={18} />}
    </span>
    {children}
  </li>
);

export const Callout = ({ children, type = "info", title }) => {
  const styles = {
    info: {
      bg: "linear-gradient(135deg, rgba(35, 121, 182, 0.12), rgba(72, 201, 176, 0.08))",
      border: "#2379B6",
      icon: <Info size={20} />,
    },
    warning: {
      bg: "linear-gradient(135deg, rgba(255, 171, 0, 0.12), rgba(255, 140, 0, 0.08))",
      border: "#FFB800",
      icon: <AlertCircle size={20} />,
    },
    tip: {
      bg: "linear-gradient(135deg, rgba(72, 201, 176, 0.12), rgba(35, 121, 182, 0.08))",
      border: "#48C9B0",
      icon: <Lightbulb size={20} />,
    },
    technical: {
      bg: "linear-gradient(135deg, rgba(160, 160, 168, 0.12), rgba(120, 120, 128, 0.08))",
      border: "#a0a0a8",
      icon: <Wrench size={20} />,
    },
  };

  const style = styles[type] || styles.info;

  return (
    <div
      style={{
        background: style.bg,
        borderLeft: `4px solid ${style.border}`,
        padding: "1.5rem 2rem",
        marginTop: "2rem",
        marginBottom: "2rem",
        borderRadius: "0 12px 12px 0",
        boxShadow: "0 8px 30px rgba(0, 0, 0, 0.3)",
        position: "relative",
      }}
    >
      {title && (
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: "0.75rem",
            marginBottom: "1rem",
            color: style.border,
            fontWeight: 700,
            fontSize: "1.1rem",
          }}
        >
          {style.icon}
          <span>{title}</span>
        </div>
      )}
      <div style={{ color: "#e0e0e5", fontSize: "1.05rem", lineHeight: 1.7 }}>{children}</div>
    </div>
  );
};

export const HighlightBox = ({ children, title }) => (
  <div
    style={{
      background: "linear-gradient(135deg, rgba(35, 121, 182, 0.15), rgba(72, 201, 176, 0.1))",
      border: "1px solid rgba(72, 201, 176, 0.3)",
      borderRadius: "16px",
      padding: "1.5rem 2rem",
      marginTop: "2rem",
      marginBottom: "2rem",
      boxShadow: "0 10px 40px rgba(35, 121, 182, 0.15)",
      position: "relative",
      overflow: "hidden",
    }}
  >
    {title && (
      <h3
        style={{
          fontSize: "1.2rem",
          fontWeight: 700,
          color: "#48C9B0",
          marginTop: 0,
          marginBottom: "1rem",
        }}
      >
        {title}
      </h3>
    )}
    <div style={{ color: "#d0d0d5", lineHeight: 1.7 }}>{children}</div>
    <div
      style={{
        position: "absolute",
        top: "-50px",
        right: "-50px",
        width: "150px",
        height: "150px",
        background: "radial-gradient(circle, rgba(72, 201, 176, 0.1), transparent)",
        borderRadius: "50%",
        pointerEvents: "none",
      }}
    />
  </div>
);

export const TableOfContents = ({ items }) => (
  <nav
    style={{
      background: "rgba(35, 121, 182, 0.08)",
      border: "1px solid rgba(35, 121, 182, 0.2)",
      borderRadius: "16px",
      padding: "1.5rem 2rem",
      marginTop: "2rem",
      marginBottom: "3rem",
    }}
  >
    <h3
      style={{
        fontSize: "1.1rem",
        fontWeight: 700,
        color: "#ffffff",
        marginTop: 0,
        marginBottom: "1rem",
        display: "flex",
        alignItems: "center",
        gap: "0.5rem",
      }}
    >
      <span>📋</span>
      <span>Sisukord</span>
    </h3>
    <ol
      style={{
        listStyle: "none",
        padding: 0,
        margin: 0,
        counterReset: "toc-counter",
      }}
    >
      {items.map((item, index) => (
        <li
          key={index}
          style={{
            marginBottom: "0.75rem",
            paddingLeft: "2rem",
            borderLeft: "2px solid rgba(72, 201, 176, 0.3)",
            transition: "all 0.2s ease",
            cursor: "pointer",
            counterIncrement: "toc-counter",
            position: "relative",
            color: "#d0d0d5",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.borderLeftColor = "#48C9B0";
            e.currentTarget.style.paddingLeft = "2.5rem";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.borderLeftColor = "rgba(72, 201, 176, 0.3)";
            e.currentTarget.style.paddingLeft = "2rem";
          }}
        >
          <span
            style={{
              position: "absolute",
              left: "0.5rem",
              color: "#48C9B0",
              fontWeight: 700,
              fontSize: "0.9rem",
            }}
          >
            {index + 1}.
          </span>
          <a
            href={`#${item.id}`}
            style={{
              color: "inherit",
              textDecoration: "none",
              fontSize: "0.95rem",
              display: "block",
            }}
          >
            {item.title}
          </a>
        </li>
      ))}
    </ol>
  </nav>
);

export const Quote = ({ children, author }) => (
  <blockquote
    style={{
      borderLeft: "4px solid #48C9B0",
      paddingLeft: "2rem",
      marginLeft: 0,
      marginTop: "2rem",
      marginBottom: "2rem",
      fontStyle: "italic",
      fontSize: "1.2rem",
      color: "#e0e0e5",
      position: "relative",
    }}
  >
    <div
      style={{
        position: "absolute",
        left: "-12px",
        top: "-10px",
        fontSize: "3rem",
        color: "#48C9B0",
        opacity: 0.3,
        fontFamily: "Georgia, serif",
      }}
    >
      "
    </div>
    <p style={{ marginBottom: author ? "0.5rem" : 0 }}>{children}</p>
    {author && (
      <footer
        style={{
          fontSize: "0.9rem",
          color: "#a0a0a8",
          fontStyle: "normal",
          marginTop: "0.5rem",
        }}
      >
        — {author}
      </footer>
    )}
  </blockquote>
);

export const Divider = () => (
  <hr
    style={{
      border: "none",
      height: "1px",
      background: "linear-gradient(to right, transparent, rgba(72, 201, 176, 0.3), transparent)",
      marginTop: "3rem",
      marginBottom: "3rem",
    }}
  />
);

export const CTAButton = ({ children, href, primary = true }) => (
  <a
    href={href}
    style={{
      display: "inline-flex",
      alignItems: "center",
      gap: "0.75rem",
      padding: "1rem 2rem",
      background: primary
        ? "linear-gradient(135deg, #2379B6, #48C9B0)"
        : "rgba(72, 201, 176, 0.15)",
      color: "#ffffff",
      textDecoration: "none",
      borderRadius: "12px",
      fontWeight: 700,
      fontSize: "1rem",
      transition: "all 0.3s ease",
      boxShadow: primary ? "0 8px 25px rgba(35, 121, 182, 0.3)" : "none",
      border: primary ? "1px solid rgba(255, 255, 255, 0.1)" : "1px solid rgba(72, 201, 176, 0.3)",
      marginTop: "2rem",
      marginBottom: "1rem",
    }}
    onMouseEnter={(e) => {
      e.currentTarget.style.transform = "translateY(-2px)";
      e.currentTarget.style.boxShadow = primary
        ? "0 12px 35px rgba(35, 121, 182, 0.4)"
        : "0 8px 25px rgba(72, 201, 176, 0.2)";
    }}
    onMouseLeave={(e) => {
      e.currentTarget.style.transform = "translateY(0)";
      e.currentTarget.style.boxShadow = primary ? "0 8px 25px rgba(35, 121, 182, 0.3)" : "none";
    }}
  >
    {children}
  </a>
);
