import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "kuidas-valida-oige-mootorioli-vanemale-autole";
const META_TITLE = "Kuidas valida õige mootoriõli vanemale autole?";
const META_DESCRIPTION =
  "Praktiline juhend, kuidas valida õige mootoriõli vanemale autole: viskoossus, spetsifikatsioonid, läbisõit ja mootori kulumisaste.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootoriõli valik, vana auto õli, mootori hooldus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogKuidasValidaOigeMootorioliVanemaleAutole() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-kuidas-valida-oige-mootorioli-vanemale-autole",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Kuidas valida õige mootoriõli vanemale autole?</Heading>

          <p>
            Vanematel autodel on mootor juba oma tööea jooksul märgatavalt kulunud. See tähendab, et õige{" "}
            <strong>mootoriõli valik</strong> ei ole lihtsalt „5W-40 ja asi ants“, vaid strateegiline otsus, mis mõjutab
            nii töökindlust, õlikulu kui ka käivitust külmaga.
          </p>

          <Heading as="h2">Miks ei piisa ainult käsiraamatu näitajast?</Heading>
          <p>
            Tehase manuaal eeldab uut või peaaegu uut mootorit. 15+ aasta ja sadade tuhandete kilomeetrite järel on
            tolerantsid suuremad, tihendid väsinumad ja saastekoormus kõrgem. Seetõttu tuleb tehase soovitusi vaadata kui
            lähtepunkti, mitte absoluutset tõde.
          </p>

          <Heading as="h2">Viskoossus: millal valida 5W-40, 10W-40 või 5W-30?</Heading>
          <p>
            <strong>Külm-viskoossus (5W, 10W)</strong> mõjutab käivitust madalatel temperatuuridel. Vanema mootoriga ja
            Eesti kliimas on enamasti mõistlik jääda 5W või 10W juurde – liiga paks õli muudab külmkäivituse raskeks.{" "}
            <strong>Sooja-viskoossus (30, 40, 50)</strong> mõjutab kaitset kuuma mootoriga. Suurema läbisõiduga
            mootorites kasutatakse sageli 40-viskoossusega õli, et hoida õlirõhku stabiilsemana ja vähendada õlikulu.
          </p>

          <Heading as="h2">Mineral, poolsünt ja täissünt – mida eelistada?</Heading>
          <p>
            <strong>Täissünteetiline õli</strong> tagab tavaliselt parema külmkäivituse ja puhtama mootori, kuid väga
            väsinud mootorites võib see esile tuua lekked ja tõsta õlikulu. <strong>Poolsünteetiline</strong> on
            paljude vanemate igapäevaautode puhul hea kompromiss. <strong>Mineralõli</strong> on pigem erand –
            kasutatakse vaid siis, kui tootja seda selgelt ette näeb või mootorikonstruktsioon on väga vana.
          </p>

          <Heading as="h2">Spetsifikatsioonid: ACEA, API ja tootjaspetsiifilised nõuded</Heading>
          <p>
            Kontrolli, et õli vastaks vähemalt tootja poolt nõutud <strong>ACEA</strong> või <strong>API</strong> klassile
            (nt ACEA A3/B4, API SL/SM). Kui autol on turbo või diisel koos DPF-iga, on kriitiline kasutada õigete
            lisanditega „low-SAPS“ õli. Vale klass võib lühendada turbo ja DPF-i eluiga märgatavalt.
          </p>

          <Heading as="h2">Läbisõit ja õlikulu: millal minna paksema õli peale?</Heading>
          <p>
            Kui vanem auto hakkab <strong>rohkem õli võtma</strong>, tasub koos diagnostikaga hinnata ka viskoossust.
            Mõõdukas üleminek 5W-30 pealt 5W-40 või 10W-40 peale võib vähendada õlikulu ja tõsta õlirõhku, kuid see ei
            tohi olla kattevariant tõsiste mehaaniliste probleemide eest.
          </p>

          <Heading as="h2">Turbo, gaasiseade ja linnasõit – erijuhtumid</Heading>
          <p>
            Turbomootor, LPG/CNG süsteem ja ülekaalus lühikesed linnasõidud koormavad õli oluliselt. Sellisel juhul on
            mõistlik kasutada kvaliteetsemat täissünteetilist õli ning lühendada <strong>õlivahetusintervalli</strong>.
          </p>

          <Heading as="h2">Kokkuvõte: vali õli mootori tegeliku seisukorra järgi</Heading>
          <p>
            Õige <strong>mootoriõli valik vanemale autole</strong> tähendab arvestamist mootori kulumisastme, läbisõidu,
            kasutusprofiili ja tootja miinimumnõuetega. Kõige odavam õli ei ole kunagi parim strateegia; mõistlik on
            investeerida õlisse, mis päriselt toetab mootori järelejäänud eluiga.
          </p>
        </article>
      </main>
    </div>
  );
}

