import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "veermiku-hooldus-vs-lappimine";
const META_TITLE = "Veermiku hooldus vs lappimine – miks ühekaupa vahetamine on kallim?";
const META_DESCRIPTION =
  "Analüüsime, miks veermiku detailide ühekaupa vahetamine tihti suurendab pikas plaanis kulusid ning kuidas süsteemne hooldus hoiab auto stabiilse ja ohutu.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "veermiku hooldus, sillaremont, stabilisaator",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVeermikuHooldusVsLappimine() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-veermiku-hooldus-vs-lappimine",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Veermiku hooldus vs “lappimine” – miks ühekaupa vahetamine tihti rohkem maksma läheb?</Heading>

          <p>
            Klassika: „vahetame ainult selle kõige halvema puksi ära, ülejäänud elavad veel“. Tulemus: kuu aja pärast uus kolin, uus töökäik, uus arve. <strong>Süsteemne veermiku hooldus</strong> on vanema auto puhul kordades mõistlikum kui juhuslik lappimine.
          </p>

          <Heading as="h2">Veermik on süsteem, mitte üksikdetail</Heading>
          <p>
            Ühel rattal töötavad koos õõtsad ja nende <strong>puksid</strong>, <strong>šarniirid</strong>, <strong>amortisaator</strong> ja vedru ning <strong>stabilisaatori vardad</strong> ja puksid. Kui üks detail on täiesti läbi, on ülejäänud tavaliselt „piiri peal“. Uue tugeva detaili lisamine väsinud komplekti võib tuua esile järgmise nõrga koha.
          </p>

          <Heading as="h2">Topelt töö = topelt kulu</Heading>
          <p>
            Kui auto tõstetakse iga paari kuu tagant üles, et „veel üks puks ära vahetada“, maksad iga kord tõste ja diagnostika, sama sõlme lahtivõtmise ja kokkupaneku ning tihti hiljem ka <strong>sillastendi</strong> uuesti. Kui teha <strong>veermik ühel teljel korraga korda</strong>, on töö maht väiksem kui kolmel eraldi visiidil sama telge lappides.
          </p>

          <Heading as="h2">Ohutus: halb veermik ei andesta hädapidurdusel</Heading>
          <p>
            Poolikult korras veermik tähendab ebastabiilset pidurdamist, ebaloogilist käitumist kurvides ja pikemat pidurdusteekonda. Ühe puksi või šarniiri tilgutamine siia-sinna ei muuda autot tervikuna turvaliseks – vaja on, et <strong>kogu telg töötaks ühtse komplektina</strong>.
          </p>

          <Heading as="h2">Rehvide ja kütusekulu mõju</Heading>
          <p>
            Poolikult korras veermik ja paigast sillanurgad kulutavad rehve ebaühtlaselt (saehambad, servad) ning tõstavad <strong>kütusekulu</strong>, sest auto „sõdib“ iseenda vastu.
          </p>

          <Heading as="h2">Süsteemne plaan vanema auto veermikule</Heading>
          <p>
            Mõistlik lähenemine: diagnoosida <strong>kogu veermik</strong>, tõsta kriitilised sõlmed prioriteediks, vahetada detailid <strong>telje või detailigrupi kaupa</strong> (mõlemad pooled korraga) ja lõpetada töö sillastendiga.
          </p>

          <Heading as="h2">Kokkuvõte: vähem kordi töökotta, rohkem väärtust iga käiguga</Heading>
          <p>
            <strong>Veermiku hooldus</strong> ei pea tähendama iga kuu ühte kolinat vähem. Kui võtta korraga süsteemne plaan, on auto juhitavus parem, kulud prognoositavamad ja tehniline ülevaatus märksa rahulikum.
          </p>
        </article>
      </main>
    </div>
  );
}
