import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "silla-ja-veermiku-kolinad";
const META_TITLE = "Silla- ja veermiku kolinad – 7 põhjust, miks neid ei tohi ignoreerida";
const META_DESCRIPTION =
  "Selgitame, miks silla- ja veermiku kolinad on vanemal autol kriitiline hoiatus: 7 peamist põhjust, miks probleemiga ei tohi oodata.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "veermiku kolinad, silla hooldus, auto ohutus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogSillaJaVeermikuKolinad() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-silla-ja-veermiku-kolinad",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Silla- ja veermiku kolinad – 7 põhjust, miks neid ei tohi ignoreerida</Heading>

          <p>
            Kui <strong>sild või veermik koliseb</strong>, on see sinu auto viis öelda: „midagi on lahti“. Vanematel autodel
            kiputakse seda võtma kui „normaalset vanaduse heli“, aga tegelikult on tegu otsese riskiga nii ohutusele kui ka rahakotile.
          </p>

          <Heading as="h2">1. Kulunud puksid ja õõtshoovad teevad juhitavuse ebastabiilseks</Heading>
          <p>
            Pragunenud või läbikulunud <strong>silmapuksid ja õõtshoovad</strong> lasevad rattal liikuda vales suunas. Tulemuseks on ujuv sõidutunne,
            „ujub rööbastes“ efekt ja ebaloogiline käitumine kurvides. Hädaolukorras tähendab see pikemat pidurdusteekonda ja kehvemat kontrolli.
          </p>

          <Heading as="h2">2. Amortisaatorite rike pikendab pidurdusteekonda</Heading>
          <p>
            Väsinud amort ei hoia ratast korralikult vastu teepinda. Iga kord, kui auto „hüppab“, kaotab rehv hetkeks haardumise. Tulemuseks on
            <strong>pikem pidurdusteekond, ABS-i sage sekkumine ja ebastabiilne pidurdamine</strong>.
          </p>

          <Heading as="h2">3. Lõtk rooliotstes ja šarniirides = ohtlik roolisüsteem</Heading>
          <p>
            Kui roolis on lõtk ja veermiku juurest tuleb kolinat, võivad kulunud olla <strong>rooliotsad, šarniirid või roolilatt</strong>.
            See ei ole ainult tülikas, vaid ohtlik: auto ei reageeri täpselt ja kriisiolukorras võib juht kaotada kontrolli.
          </p>

          <Heading as="h2">4. Ebaühtlane rehvikulumine tõstab püsikulusid</Heading>
          <p>
            Valed nurgad ja lõtkud silladetailides tekitavad <strong>ebaühtlast rehvikulumist</strong>. Rehv läheb „saagima“ või kulub ühelt servalt kiiresti maha.
            Rehvid on kallid; aja jooksul on see otsene rahaline kahju.
          </p>

          <Heading as="h2">5. Sillastendi ignoreerimine pärast löökauku või avariid</Heading>
          <p>
            Löök sügavasse auku, äärekivisse sõit või kerge avarii võivad lüüa silla nurgad paigast. Kui <strong>sillastendi ei tehta</strong>,
            tähendab see pidevat rehvikahju, suuremat kütusekulu ja halvenenud juhitavust.
          </p>

          <Heading as="h2">6. Kolin on tihti esimene hoiatus enne reaalselt ohtlikku riket</Heading>
          <p>
            Enne kui detail päriselt katki läheb, hakkab ta tavaliselt <strong>kolisema, nagisema, krigisema</strong>. Kui seda signaali eirata,
            võib üks hetk midagi sõidu ajal lahti tulla – ja siis ei ole enam tegu ainult mugavuse küsimusega.
          </p>

          <Heading as="h2">7. Üks vigane detail koormab kogu ülejäänud veermikku</Heading>
          <p>
            Lõtk ühes puksis või amordis ei tööta vaakumis. See koormab üle <strong>teisi pukse, rehve, roolimehhanismi ja isegi keret</strong>.
            Varajane sekkumine hoiab ära lumepalli efekti, kus ühel hetkel tuleb pool veermikku korraga välja vahetada.
          </p>

          <Heading as="h2">Kokkuvõte: kolin ei ole „vanaduse heli“, vaid tegevuskäsk</Heading>
          <p>
            <strong>Silla- ja veermiku kolinad</strong> on selge hoiatus, mida ei tohi ignoreerida. Varajane kontroll ja remont säästavad rehve,
            vähendavad kütusekulu ja mis kõige tähtsam – hoiavad auto juhitavana ka siis, kui peaksid tegema ootamatu manöövri.
          </p>
        </article>
      </main>
    </div>
  );
}
