import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "vanema-auto-kaivitamisraskused-kulmaga";
const META_TITLE = "Vanema auto käivitamisraskused külmaga – tehnilised põhjused ja lahendused";
const META_DESCRIPTION =
  "Analüüsime, miks vanem auto ei taha külmaga käivituda: aku, õli, hõõgküünlad, kütusesüsteem ja starter ning mida teha.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "külmkäivitus, aku, hõõgküünlad",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVanemaAutoKaivitamisraskusedKulmaga() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-vanema-auto-kaivitamisraskused-kulmaga",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Vanema auto käivitamisraskused külmaga – tehnilised põhjused ja lahendused</Heading>

          <p>
            Talv paneb <strong>vanemad autod</strong> kiiresti proovile. Kui mootor ei taha käivituda või teeb seda raskelt,
            ei ole süüdlaseks ainult „külm ilm“, vaid konkreetne tehniline pudelikael.
          </p>

          <Heading as="h2">Aku – esimene nõrk lüli</Heading>
          <p>
            Madal temperatuur vähendab aku mahtuvust ja käivitusvoolu. Kui <strong>aku on üle 4–5 aasta vana</strong>,
            klemmid oksüdeerunud või generaator ei lae piisavalt, annab see külmaga kohe tunda. Lahendus: aku test, klemmide
            puhastus, vajadusel vahetus.
          </p>

          <Heading as="h2">Mootoriõli viskoossus</Heading>
          <p>
            Liiga paks või vananenud õli muudab starteri töö raskeks ja aeglaseks ning ei kaitse mootorit käivituse esimesel
            kriitilisel hetkel. <strong>Õige viskoossusega õli</strong> (nt 5W-40 või 5W-30, sõltuvalt mootorist) ja õigeaegne
            õlivahetus on otsene investeering talvisesse käivitumisse.
          </p>

          <Heading as="h2">Diislitel: hõõgküünlad ja juhtimine</Heading>
          <p>
            Kui diiselmootor käivitub külmaga väga raskelt või ainult pika ragistamise järel, on esimesed kahtlusalused{" "}
            <strong>hõõgküünlad ja nende relee/juhtplokk</strong>. Üks või mitu surnud hõõgküünalt teevad käivituse eriti karmiks
            just vanematel mootoritel.
          </p>

          <Heading as="h2">Kütuse kvaliteet ja filter</Heading>
          <p>
            Ummistunud kütusefilter või talveks sobimatu kütus on klassikaline põhjus, miks mootor „võtab“, aga ei käivitu. Talvel
            on eriti oluline, et <strong>kütusefilter oleks korras</strong> ja paagis oleks talvele vastav kütus.
          </p>

          <Heading as="h2">Starter ja massijuhtmed</Heading>
          <p>
            Kulunud starter, kehvad massiühendused ja oksüdeerunud kaablid toovad kaasa <strong>aeglase väntamise</strong>.
            Vanematel autodel on massijuhtmete läbimädanemine väga levinud probleem. Ühe kaabli puhastus või vahetus võib teha imesid.
          </p>

          <Heading as="h2">Kokkuvõte: käivitusprobleem ei ole „vanaduse“ paratamatus</Heading>
          <p>
            <strong>Vanema auto käivitamisraskused külmaga</strong> on lahendatavad, kui läheneda metoodiliselt: aku, õli,
            hõõgküünlad, kütus ja starter järjekorras üle vaadata. Ennetav hooldus sügisel on odavam kui puksiir hommikul.
          </p>
        </article>
      </main>
    </div>
  );
}

