import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "mootori-ulekuumenemine";
const META_TITLE = "Mootori ülekuumenemine: kas “üks kord korraks” või juba plokikaane teema?";
const META_DESCRIPTION =
  "Arutame, mida tähendab mootori ülekuumenemine, millal teha plokikaane tihendi test ning kuidas jahutussüsteemi tervikuna hinnata.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootori ülekuumenemine, plokikaane tihend",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMootoriUlekuumenemine() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-mootori-ulekuumenemine",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <header>
            <Heading as="h1">Mootori ülekuumenemine: kas “üks kord korraks” või juba plokikaane teema?</Heading>
            <h2>Alternatiivsed pealkirjad</h2>
            <ul>
              <li>Ülekuumenemine punases: millal tuleb plokikaane tihend kohe üle kontrollida?</li>
              <li>Mootori temperatuur punases – kas võid lihtsalt edasi sõita?</li>
              <li>Mida teeb üks ülekuumenemine mootoriga reaalselt?</li>
            </ul>
            <p>
              “Läks korraks punasesse, aga jahtus kohe maha” – see lause on tavaliselt proloog kallile mootoriremondile. Ka lühiajaline ülekuumenemine võib tekitada plokikaane mikromoonutusi, tihendi kahjustusi ja jahutussüsteemi õhutäis.
            </p>
          </header>

          <section>
            <Heading as="h2">Mis loetakse “korraks ülekuumenemiseks”?</Heading>
            <p>Reaalne ülekuumenemine tähendab, et temperatuurinäidik jõuab punasesse, paisupaagi kork laseb aururõhku välja, ventilaator töötab täisvõimsusel ja mootor kaotab jõudu.</p>
          </section>

          <section>
            <Heading as="h2">Potentsiaalne kahju</Heading>
            <ul>
              <li><strong>Plokikaane mikromoonutus</strong></li>
              <li><strong>Plokikaane tihendi kahjustus</strong></li>
              <li><strong>Õhk jahutussüsteemis</strong></li>
              <li><strong>Plastdetailide vananemine</strong></li>
            </ul>
          </section>

          <section>
            <Heading as="h2">Millal teha plokikaane tihendi test?</Heading>
            <p>Kui pärast ülekuumenemist on mullid paisupaagis, jahutusvedelik langeb, salongi soojendus töötab ebastabiilselt või mootor käivitub raskemalt.</p>
          </section>

          <section>
            <Heading as="h2">Jahutussüsteemi audit</Heading>
            <p>Vajalik on kontrollida veepumpa, radiaatorit, ventilaatorit, voolikuid ja paisupaagi korki ning tagada õige jahutusvedelik.</p>
          </section>

          <section>
            <Heading as="h2">Mootori temperatuur on hiljuti punases käinud?</Heading>
            <p>
              <a href="/kontakt">Broneeri Nisbelis jahutussüsteemi audit ja plokikaane tihendi test</a>, et selgitada välja, kas kahju on tekkinud või saab veel ennetada.
            </p>
          </section>
        </article>
      </main>
    </div>
  );
}
