import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "veermiku-kolinad-selgeks";
const META_TITLE = "Veermiku kolinad selgeks – kuidas heli järgi aru saada, mis detail annab alla?";
const META_DESCRIPTION =
  "Veermiku kolinad ei ole lihtsalt tüütud helid. Õpi heli järgi eristama pukside, amortide, šarniiride ja rooliotste probleeme ning know, millal teenindusse minna.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "veermiku kolinad, šarniirid, pukid, amortisaator", 
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVeermikuKolinadSelgeks() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-veermiku-kolinad-selgeks",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Veermiku kolinad selgeks – kuidas heli järgi aru saada, mis detail annab alla?</Heading>

          <p>
            Veermiku kolin ei ole „vanale autole normaalne“. Iga klõps, nagin või müts tähistab mingit lõtku, pragunenud pukki või kulunud liigendit. Mida varem reageerid, seda odavamalt pääsed – ja seda turvalisem on auto.
          </p>

          <Heading as="h2">Terav klõps üle augu või äärekivi – šarniir või rooliots</Heading>
          <p>
            Kui <strong>üle löökaugu või äärekivi käies kostab üksik terav klõps</strong>, on kahtlustatavad tavaliselt šarniirid (õõtsaotsad) või rooliotsad ja -vardad. Need detailid hoiavad ratast õiges suunas. Kui nad läbi lähevad, muutub juhitavus ebakindlaks ja äärmuslikul juhul võib detail sõidu ajal lahti tulla.
          </p>

          <Heading as="h2">Nagin, kriuks ja „voodi vedru“ heli – pukid ja stabikavardad</Heading>
          <p>
            <strong>Kummipukid ja stabilisaatori vardad</strong> annavad endast märku kriuksu, nagina ja vedru-laadse heliga, eriti kui auto kiigub (lamav politsei, kõnnitee serv) või kui rooli kergelt liigutad ühele ja teisele poole. Väsinud puks tähendab, et ratta geomeetria liigub koormuse all paigast, rehvid kuluvad viltu ja auto „ujuv“ käitumine süveneb.
          </p>

          <Heading as="h2">Tuim müts ja jäik löök – amortisaator ja vedrustus</Heading>
          <p>
            Kui teeauk tundub nagu „haamriga vastu keret“, on tihti mängus <strong>väsinud amort või katkine vedru</strong>. Auto ei summuta lööki, vaid annab selle otse kerele edasi. Lisaks mugavusele kannatavad pidurdusteekond ning veermiku teised detailid, mis saavad suuremad löögid.
          </p>

          <Heading as="h2">Metalliline kõrin kiiruse kasvades – rattalaager või pidurisüsteem</Heading>
          <p>
            <strong>Monotoonne undamine või kõrin</strong>, mis muutub koos kiirusega, viitab enamasti rattalaagrile või pidurisüsteemi probleemile (kettad, klotsid, kivike vahel). Rattalaager ei parane ise – see läheb ainult halvemaks.
          </p>

          <Heading as="h2">Miks kolinat ei tohi ignoreerida?</Heading>
          <ul>
            <li>Detail, mis „ainult koliseb“, võib homme juba laiali lennata.</li>
            <li>Üks lõtk koormab üle teisi komponente – remondima peab lõpuks pool veermikut.</li>
            <li>Tehniline ülevaatus võib tulla <strong>märgukirjadega või läbikukkumisega</strong>.</li>
          </ul>

          <Heading as="h2">Millal on aeg teenindusse tulla?</Heading>
          <p>Kui kolin on püsiv, auto ujuv käitumine on kasvanud või rool on „logisev“, ning rehvid kuluvad ebaühtlaselt või tekivad saehambad, on aeg lasta <strong>veermik üle vaadata</strong> ja teha proovikäik koos mehaanikuga. Mida varem sekkud, seda väiksem on arve ja seda parem on juhitavus – eriti oluline vanema auto puhul.</p>
        </article>
      </main>
    </div>
  );
}
