import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "kasutatud-auto-hammasrihm";
const META_TITLE = "Kasutatud auto ja hammasrihm – kas see on päriselt vahetatud?";
const META_DESCRIPTION =
  "Ostad kasutatud auto ja müüja väidab, et hammasrihm on vahetatud. Näitame, kuidas hinnata info tõepärasust ja millal rihm ikkagi vahetada.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "kasutatud auto, hammasrihma ajalugu",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogKasutatudAutoHammasrihm() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-kasutatud-auto-hammasrihm",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Kasutatud auto ja hammasrihm – kas see on päriselt vahetatud?</Heading>

          <p>
            Klassikaline lause kuulutuses: <strong>„hammasrihm vahetatud“</strong>. Tegelik küsimus on, millal, millega ja kelle poolt. Kui ostad auto ja rihm on tegelikult tundmatu, paned end teadlikult suure remondiriski alla.
          </p>

          <Heading as="h2">Dokumendid räägivad, mitte ainult jutt</Heading>
          <p>
            Usaldusväärse info tunnused on töökoja <strong>arve või tööleht</strong>, kuupäev ja odomeetri näit ning kasutatud varuosade tootjad. Ilma selleta on kõik muu lihtsalt jutt.
          </p>

          <Heading as="h2">Kleebis kapoti all</Heading>
          <p>
            Paljud töökodad kleebivad <strong>märgise hammasrihma vahetuse kohta</strong>. Sealt näed kuupäeva ja läbisõitu ning mõnikord töökoja kontakti. Kui kleebist ja dokumente pole, on suur tõenäosus, et keegi täpselt ei tea, millal rihm tehtud sai.
          </p>

          <Heading as="h2">Visuaalne vaatlus – mida see annab?</Heading>
          <p>
            Kaane alt piiludes ei tohiks rihm olla praguline ega narmendav, pingutid ei tohiks undada ja veepumba ümbruses ei tohiks olla lekkimise jälgi. Kuid <strong>ka uus rihm võib välja näha vana ja vastupidi</strong> – ainult visuaalile toetuda ei saa.
          </p>

          <Heading as="h2">Millal on mõistlik rihm igaks juhuks vahetada?</Heading>
          <p>
            Kui dokumendid puuduvad või on segased, plaanid autot <strong>kauem pidada</strong> või tegu on mootoriga, kus rihma purunemisel on tagajärg kindel mootorikahjustus, siis on kõige mõistlikum teha <strong>hammasrihma komplekti vahetus</strong> kohe ostu järel.
          </p>

          <Heading as="h2">Kokkuvõte: parem kindel teadmine kui teoreetiline „rihm just tehtud“</Heading>
          <p>
            <strong>Kasutatud auto hammasrihma ajalugu</strong> on kriitiline riskikoht. Ilma selge tõendita on odavam ja targem investeerida korrektsesse vahetusse kui loota müüja lubadusele ja riskida suure mootoriremondiga.
          </p>
        </article>
      </main>
    </div>
  );
}
