import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "regulaarne-diagnostika-vanemal-autol";
const META_TITLE = "Miks on regulaarne diagnostika vanemal autol odavam kui ootamatu rike?";
const META_DESCRIPTION =
  "Selgitame, miks regulaarne autodiagnostika vanemal sõidukil aitab ennetada kalleid rikkeid ja puksiiriarveid.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "autodiagnostika, check engine, veakoodid",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogRegulaarneDiagnostikaVanemalAutol() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-regulaarne-diagnostika-vanemal-autol",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Miks on regulaarne diagnostika vanemal autol odavam kui “ootamatu” rike?</Heading>

          <p>
            Vanem auto võib sõita kaua ja edukalt, kui omanik mängib ennetavat mängu. <strong>Regulaarne diagnostika</strong> ei ole „lisakulu“,
            vaid tööriist kulude kontrolli all hoidmiseks. Vastasel juhul dikteerib plaani puksiir ja remondiarve.
          </p>

          <Heading as="h2">Varajased veakoodid vs. hiline kapitaalremont</Heading>
          <p>
            Enamikul tänapäeva autodel salvestab juhtplokk <strong>veakoode</strong> tunduvalt enne seda, kui juht midagi tunda või näha jõuab.
            Regulaarne diagnostika püüab need koodid kinni juba algfaasis, kui probleem on tihti lahendatav odava anduri, juhtme või tihendi
            vahetusega – mitte terve agregaadi remondiga.
          </p>

          <Heading as="h2">Check engine tuli ei ole dekoratsioon</Heading>
          <p>
            Kui armatuuris põleb pidevalt <strong>“check engine”</strong>, muutub see psühholoogiliselt „normaalseks taustamüraks“. See on halb harjumus.
            Tuli põleb põhjusel ja selle ignoreerimine tähendab, et võimalik odav ja varajane lahendus lastakse käest.
          </p>

          <Heading as="h2">Vanemal autol on sensorid ja pistikud eriti tundlikud</Heading>
          <p>
            Aastatega kogunevad niiskus, mustus ja oksüdatsioon <strong>pistikutesse ja anduritesse</strong>. See tekitab valenäite, katkestusi ja
            ebastabiilset tööd. Diagnostika aitab kaardistada, millised süsteemid käituvad „piiri peal“, enne kui need täitsa alla annavad.
          </p>

          <Heading as="h2">Kütusekulu ja jõudlus – peidetud rahaauk</Heading>
          <p>
            Väike kõrvalekalle lambdaanduris, MAF-anduris või süütesüsteemis ei pruugi veel lampi põlema panna, aga <strong>kütusekulu tõuseb ja jõudlus langeb</strong>.
            Regulaarne diagnostika + proovikäik annavad selge pildi, kas mootor töötab oma potentsiaali piiril või raiskab lihtsalt kütust.
          </p>

          <Heading as="h2">DPF, EGR ja heitgaasisüsteem – kallid mängijad</Heading>
          <p>
            Diiselmootorite <strong>DPF ja EGR</strong> on tuntud kui „rahakoti killerid“, kui neid ignoreerida. Varajased vead, ebapiisavad
            regenereerimised, ummistused – diagnostika annab signaali enne, kui filter on täiesti kinni ja ainus variant on kallis vahetus.
          </p>

          <Heading as="h2">Diagnostika kui hooldusprotsessi osa, mitte erakorraline teenus</Heading>
          <p>
            Ideaalne mudel vanema auto jaoks: <strong>diagnostika korra aastas</strong> või iga suurema hoolduse raames. Selline lähenemine annab teenindusele
            tervikpildi – mitte ainult sellest, mis juba katki on, vaid ka sellest, mis on kohe minemas.
          </p>

          <Heading as="h2">Kokkuvõte: planeeritud kontroll on alati odavam kui ootamatu seisak</Heading>
          <p>
            <strong>Regulaarne autodiagnostika</strong> on odav kindlustuspoliis. See vähendab puksiiri, ootamatute rikete ja ajakriitiliste remonditööde riski.
            Vanem auto vajab plaanipärast lähenemist – diagnostika on selle plaani tuumikkomponent.
          </p>
        </article>
      </main>
    </div>
  );
}
