import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "mootori-tuhikaigu-koikuvus";
const META_TITLE = "Mootori tühikäigu kõikuvus vanematel autodel – 8 levinumat põhjust";
const META_DESCRIPTION =
  "Selgitame, miks vanema auto mootor tühikäigul kõikuma hakkab: vaakumlekked, andurid, süütesüsteem, pihustid ja mootori padjad.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "tühikäigu probleem, vaakumleke, süütesüsteem",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMootoriTuhikaiguKoikuvus() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-mootori-tuhikaigu-koikuvus",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Mootori tühikäigu kõikuvus vanematel autodel – 8 levinumat põhjust</Heading>

          <p>
            Vanemate autode puhul on <strong>ebaühtlane tühikäik</strong> väga tavaline kaebus. Pööre käib üles-alla, auto väriseb foori taga, vahel isegi sureb välja. Põhjuseid on mitu – ja tihti on mängus mitu korraga.
          </p>

          <Heading as="h2">1. Vaakumlekked</Heading>
          <p>
            Kulunud või pragunenud <strong>vaakumvoolikud ja sisselaskekollektori tihendid</strong> lasevad mootorisse lisaõhku, millega juhtplokk ei arvesta. Tulemuseks on lahja segu ja kõikuv tühikäik.
          </p>

          <Heading as="h2">2. Must tühikäigu regulaator või gaasiklapp</Heading>
          <p>
            Vanematel autodel koguneb gaasiklapi ja kanalite ümber <strong>õli ja tahm</strong>. Tühikäigu regulaator või gaasiklapp ei liigu sujuvalt – pöörded „pulsseerivad“.
          </p>

          <Heading as="h2">3. MAF / MAP anduri probleemid</Heading>
          <p>
            Kui <strong>õhuhulgaandur (MAF) või kollektorirõhu andur (MAP)</strong> annab vale signaali, arvab juhtplokk, et mootor hingab rohkem või vähem õhku kui tegelikult. Kütusekogus ei klapi ja tühikäik muutub ebastabiilseks.
          </p>

          <Heading as="h2">4. Süütesüsteemi rikked</Heading>
          <p>
            <strong>Süüteküünlad, süütepoolid, süütekaablid</strong> – kui üks silinder ei sütti korrektselt, on tühikäigul tunda värinat ja kogelemist ning tihti kasvab ka kütusekulu.
          </p>

          <Heading as="h2">5. Mustad või lekkivad pihustid</Heading>
          <p>
            Pihustid võivad ebavõrdselt kütust doseerida või tilkuda, mis tekitab ebastabiilset põlemist just tühikäigul.
          </p>

          <Heading as="h2">6. Mootoripadjad</Heading>
          <p>
            Kulunud <strong>mootoripadjad</strong> annavad mootorivibratsiooni täisulatuses kerele – juht tajub seda kui tugevat vibratsiooni, kuigi mootor ise võib töötada korrektselt.
          </p>

          <Heading as="h2">7. Kütusesüsteemi rõhu probleemid</Heading>
          <p>
            Kulunud <strong>kütusepump, rõhuregulaator või ummistunud filter</strong> võivad põhjustada tühikäigul kõikuva kütuserõhu, eriti koormusi vahetades.
          </p>

          <Heading as="h2">8. Mootori mehaaniline kulumine</Heading>
          <p>
            Väga suure läbisõiduga mootoritel võivad kulunud klapid, rõngad või survevahe silindrite vahel põhjustada ebaühtlast töötsüklit, mida tühikäigul on kõige enam tunda.
          </p>

          <Heading as="h2">Millal on aeg teenindusse minna?</Heading>
          <p>
            Kui mootor sureb foori taga välja, tühikäik kõigub tugevalt, check engine tuli põleb või kütusekulu on märgatavalt tõusnud, tasub probleem süstemaatiliselt diagnoosida.
          </p>

          <Heading as="h2">Kokkuvõte</Heading>
          <p>
            <strong>Tühikäigu probleemid</strong> on sümptom, mitte diagnoos. Vanemal autol võivad korraga mängus olla nii vaakumlekked, must gaasiklapp, väsinud süütesüsteem kui ka kulunud padjad. Süsteemne diagnostika on odavam kui juhuslik „andurite pimesi vahetamine“.
          </p>
        </article>
      </main>
    </div>
  );
}
