import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "millal-tasub-teha-mootori-loputus";
const META_TITLE = "Millal tasub teha mootori loputus (engine flush) ja millal see on ohtlik?";
const META_DESCRIPTION =
  "Võtame lahti, millal mootori loputus aitab ja millal võib see vanale mootorile rohkem kahju kui kasu teha.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "mootori loputus, engine flush, vanem auto hooldus",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogMillalTasubTehaMootoriLoputus() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-millal-tasub-teha-mootori-loputus",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Millal tasub teha mootori loputus (engine flush) ja millal see on ohtlik?</Heading>

          <p>
            <strong>Mootori loputus</strong> kõlab lihtsa ja ahvatleva lahendusena: valad vedeliku sisse, lased töötada ja kõik
            mustus on läinud. Reaalsus on detailsem, eriti vanemate mootorite puhul.
          </p>

          <Heading as="h2">Mis on mootori loputus?</Heading>
          <p>
            Engine flush on spetsiaalne lisaaine, mis segatakse vana õliga ja lastakse mootoril lühikest aega töötada. Selle
            eesmärk on <strong>lahustada setteid ja lakke</strong>, et need vana õliga koos välja voolaksid.
          </p>

          <Heading as="h2">Millal võib loputusest kasu olla?</Heading>
          <ul>
            <li>Kasutatud auto, mille <strong>hooldusajalugu on ebamäärane</strong>, kuid mootor töötab ühtlaselt.</li>
            <li>Mootor, kus õli on pikalt vahetamata olnud, kuid pole tugevaid mehaanilisi kolinaid.</li>
            <li>Juhtumid, kus klapikambri kaane alt on näha lakikihti, kuid mitte paksu muda.</li>
          </ul>

          <Heading as="h2">Millal võib loputus teha rohkem kahju kui kasu?</Heading>
          <p>
            Väga vana ja tugevalt kulunud mootor, kus sees on <strong>paks sete</strong>, võib loputuse järel hakata lekkima või
            kaotada õlirõhku. Põhjus: sette eemaldamine võib avada mikrolõhed tihendites ja loputatud mustus võib liikuda
            õlikanalitesse ja sõelale.
          </p>

          <Heading as="h2">Turbo ja loputus – eriti ettevaatlik</Heading>
          <p>
            Turbomootorites on õlikanalid kitsamad ja tundlikumad. Kui loputus <strong>lahti tõmbab sette turbo õlituskanalist</strong>,
            võib osa sellest jääda pidama ja põhjustada määrimise kadumist. Seetõttu peab turbolaaduri puhul loputus olema
            läbimõeldud, mitte automaatne otsus.
          </p>

          <Heading as="h2">Alternatiiv: tihedam õlivahetus kvaliteetse õliga</Heading>
          <p>
            Sageli on konservatiivsem ja turvalisem lahendus <strong>lühendatud õlivahetusintervall</strong> ja kvaliteetne
            pesuomadustega õli. Mitme järjestikuse vahetusega saab mustuse taset ohutult alla viia ilma agressiivse loputuseta.
          </p>

          <Heading as="h2">Kokkuvõte: loputus ei ole must-have, vaid riskijuhtimise otsus</Heading>
          <p>
            <strong>Mootori loputus vanal autol</strong> võib anda väga ilusa tulemuse või lõhkuda piiri peal oleva mootori
            lõplikult. Enne otsust tasub hinnata mootori reaalseid helisid, õlikulu, sete taset ja pidada nõu pädeva töökojaga.
          </p>
        </article>
      </main>
    </div>
  );
}

