import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "vanema-auto-hoolduskalender";
const META_TITLE = "Kuidas planeerida vanema auto hooldus aastaks ette – praktiline hoolduskalender";
const META_DESCRIPTION =
  "Koostame vanema auto jaoks praktilise aastase hoolduskalendri: mida teha kevadel, suvel, sügisel ja talvel, et vältida ootamatuid rikkeid.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "hoolduskalender, vanem auto hooldus, aastaplaan",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogVanemaAutoHoolduskalender() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-vanema-auto-hoolduskalender",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">Kuidas planeerida vanema auto hooldus aastaks ette – praktiline hoolduskalender</Heading>

          <p>
            Vanem auto vajab <strong>läbimõeldud hoolduskalendrit</strong>, mitte ainult „remonti siis, kui katki läheb“. Aastaplaan aitab jagada kulusid ühtlasemalt ja vähendada ootamatute rikete riski.
          </p>

          <Heading as="h2">Kevad: talvejärgne audit</Heading>
          <ul>
            <li><strong>Rehvid</strong> – talverehvide kulumine, suverehvide seisukord, rehvirõhud.</li>
            <li><strong>Veermik</strong> – talvel tekkinud kolinad, lõtkud, sillastendi vajadus.</li>
            <li><strong>Mootoriõli ja filtrid</strong>, kui viimasest vahetusest on üle 10–15k km või aasta.</li>
            <li><strong>Pidurid</strong> – kettad, klotsid, supportid (rooste ja kinni jäämine).</li>
          </ul>

          <Heading as="h2">Suvi: jahutus ja kliima fookuses</Heading>
          <ul>
            <li><strong>Jahutusvedelik</strong> – tase, värvus, lekete kontroll, vajadusel vahetus.</li>
            <li><strong>Radiaatori ja kondensaatori puhastus</strong> putukatest ja mustusest.</li>
            <li><strong>Kliimaseadme kontroll</strong> – külma tootmine, salongifilter.</li>
            <li><strong>Pikemate sõitude eelkontroll</strong> – õli, jahutus, rehvid, varuratas, tööriistad.</li>
          </ul>

          <Heading as="h2">Sügis: ettevalmistus talveks</Heading>
          <ul>
            <li><strong>Talverehvid</strong> – mustrisügavus, tootmisaasta, rõhud.</li>
            <li><strong>Aku test</strong> – vanus, pingelang, laadimine.</li>
            <li><strong>Soojendussüsteem</strong> – salongiradikas, ventilaator, siibrid, klaaside udu.</li>
            <li><strong>Tihendid ja uksed</strong> – silikooni ja määrde kasutamine külmumiste vältimiseks.</li>
          </ul>

          <Heading as="h2">Talv: käivitus ja ohutus</Heading>
          <ul>
            <li><strong>Õige mootoriõli viskoossus</strong> – et käivitus külmaga oleks lihtsam.</li>
            <li><strong>Diislitel hõõgküünalde ja süsteemi kontroll</strong>.</li>
            <li><strong>Tuled</strong> – lähituled, kaug-, udutuled, numbrituled; nähtavus on kriitiline.</li>
            <li><strong>Pidurivedelik</strong> – vahetus iga 2–3 aasta järel, et vältida keemist ja korrosiooni.</li>
          </ul>

          <Heading as="h2">Kord aastas: baas-hoolduspakett</Heading>
          <p>Sõltumata läbisõidust on vanema auto puhul mõistlik teha kord aastas:</p>
          <ul>
            <li><strong>Õlivahetus + õlifilter</strong>;</li>
            <li><strong>Salongifilter ja õhufilter</strong> (vähemalt kontroll, tihti ka vahetus);</li>
            <li><strong>Diagnostika</strong> – veakoodide kontroll, proovikäik;</li>
            <li><strong>Visuaalne ülevaatus</strong> – lekked, rooste, veermik, pidurid.</li>
          </ul>

          <Heading as="h2">Kolme- kuni viieaastane vaade: suured tööd</Heading>
          <p>Pikemas plaanis tasub vanemal autol jälgida:</p>
          <ul>
            <li><strong>Hammasrihma või keti hooldusi</strong> (vastavalt tootja soovitusele);</li>
            <li><strong>Amortide ja veermiku detailide</strong> kumulatiivset kulumist;</li>
            <li><strong>Siduri ja käigukasti</strong> käitumist (libisemine, kolinad, rasked käigud).</li>
          </ul>

          <Heading as="h2">Kokkuvõte: vanema auto hooldus ei tohi olla juhuslik</Heading>
          <p>
            <strong>Aastane hoolduskalender</strong> annab sulle kontrolli – mitte auto ei üllata sind, vaid sina juhid tema elutsüklit. Planeeritud hooldused on alati odavamad ja rahulikumad kui
            ootamatud remondid keset hooaega.
          </p>
        </article>
      </main>
    </div>
  );
}
