import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "dpf-ja-linnasoit";
const META_TITLE = "DPF filtreerib, kuni ei filtreeri enam – kuidas linnasõit vanema diisli tapab?";
const META_DESCRIPTION =
  "Selgitame, kuidas lühikesed linnasõidud ummistavad DPF-i, miks regenereerimine ei õnnestu ja millal on veel võimalik filter päästa.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "DPF, regenereerimine, diisel", 
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogDpfJaLinnasoit() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-dpf-ja-linnasoit",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <Heading as="h1">DPF filtreerib, kuni ei filtreeri enam – kuidas linnasõit vanema diisli heitgaasisüsteemi tapab?</Heading>

          <p>
            Diiselmootor ja <strong>DPF</strong> saavad hästi läbi seni, kuni auto saab aeg-ajalt korralikult kuuma. Puhas linnasõit, lühikesed otsad ja külmad käivitused on kombinatsioon, mis tapab filtri vaikselt, aga kindlalt.
          </p>

          <Heading as="h2">Kuidas DPF töötab?</Heading>
          <p>DPF püüab kinni <strong>tahma ja osakesed</strong> heitgaasidest, teatud intervalliga teeb auto <strong>regenereerimist</strong> ja põletab tahma CO₂-ks, et filter jääks töövõimeliseks.</p>

          <Heading as="h2">Miks linnasõit on halb?</Heading>
          <p>
            Regenereerimine vajab piisavalt kõrget heitgaasi temperatuuri, aega ja ühtlast kiirust. Lühikesed otsad ja start-stop sõidud tähendavad, et DPF ei jõua kunagi lõpuni regenereerida ja kogub ainult juurde.
          </p>

          <Heading as="h2">Tüüpilised sümptomid</Heading>
          <ul>
            <li>mootor läheb <strong>limp mode’i</strong>;</li>
            <li>tõuseb <strong>kütusekulu</strong>;</li>
            <li>ventikas jookseb tihti järgi;</li>
            <li>armatuuris ilmub DPF või check engine hoiatus.</li>
          </ul>

          <Heading as="h2">Sundregenereerimine ei lahenda kõike</Heading>
          <p>
            Sundregenereerimine aitab, kui filter pole veel täis tuhka ja lahendatakse ka põhjus (lekked, sensorid, sõiduprofiil). Kui jätkad samamoodi linnasõite, on DPF varsti jälle hädas.
          </p>

          <Heading as="h2">Kuidas vanema diisliga targalt toimetada?</Heading>
          <ul>
            <li>korra-kaks nädalas tee <strong>pikem maanteesõit</strong>;</li>
            <li>kasuta õiget <strong>ACEA/ tootja nõudega õli</strong>;</li>
            <li>pööra tähelepanu auto käitumise muutustele.</li>
          </ul>

          <Heading as="h2">Millal on veel päästa ja millal on hilja?</Heading>
          <p>Päästa saab, kui filter on tahmast ummistunud ja reageerid esimeste sümptomite ajal. Hilja on siis, kui kärg on läbi põlenud või mehaaniliselt kahjustunud.</p>

          <Heading as="h2">Kokkuvõte</Heading>
          <p>
            <strong>Vanem diisel koos DPF-iga</strong> ei ole mõeldud puhtalt 2–5 km linnaringide tarbeks. Kas planeeri regulaarsed „puhastussõidud“ või mõtle, kas diisel sobib sinu kasutusprofiilile.
          </p>
        </article>
      </main>
    </div>
  );
}
