import React from "react";
import { useArticleMeta } from "../../src/lib/useArticleMeta";
import { articleBaseStyles, articleContainerStyles, articleHeadingStyles } from "../../src/lib/articleStyles";
import { BlogHero } from "../../src/lib/blogHero";

const SLUG = "karterituulutus-pcv";
const META_TITLE = "Karterituulutus (PCV): väike sõlm, mis paneb otsustama õlikulu ja tihendite saatuse";
const META_DESCRIPTION =
  "Selgitame, miks PCV-süsteemi hooldus on kriitiline: kuidas ummistunud karterituulutus tekitab õlilekkeid, tõstab rõhku ja lõhub tihendeid.";

const META_TAGS = [
  { name: "description", content: META_DESCRIPTION },
  { property: "og:type", content: "article" },
  { property: "og:title", content: META_TITLE },
  { property: "og:description", content: META_DESCRIPTION },
  { property: "og:url", content: `https://sinu-domeen.ee/blogi/${SLUG}` },
];

const STRUCTURED_DATA = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  headline: META_TITLE,
  description: META_DESCRIPTION,
  author: { "@type": "Person", name: "LEISSON" },
  genre: "Automotive",
  keywords: "karterituulutus, PCV, õlikulu",
  articleSection: "Autohooldus",
  mainEntityOfPage: {
    "@type": "WebPage",
    "@id": `https://sinu-domeen.ee/blogi/${SLUG}`,
  },
};

const Heading = ({ as: Tag, children }) => (
  <Tag style={Tag === "h1" ? articleHeadingStyles.h1 : articleHeadingStyles.h2}>{children}</Tag>
);

export default function BlogKarterituulutusPCV() {
  useArticleMeta({
    title: META_TITLE,
    description: META_DESCRIPTION,
    metaTags: META_TAGS,
    structuredData: STRUCTURED_DATA,
    schemaId: "schema-karterituulutus-pcv",
  });

  return (
    <div style={articleBaseStyles}>
      <main style={articleContainerStyles}>
        <article>
          <BlogHero slug={SLUG} title={META_TITLE} />
          <header>
            <Heading as="h1">Karterituulutus (PCV): väike sõlm, mis paneb otsustama õlikulu ja tihendite saatuse</Heading>
            <h2>Alternatiivsed pealkirjad</h2>
            <ul>
              <li>PCV-süsteem: miks ummistunud karterituulutus hävitab su tihendid?</li>
              <li>Karterituulutus ja õlikulu: nähtamatu süüdlane, mida peaaegu keegi ei hoolda</li>
              <li>Väike detail, suur mõju: karterituulutus (PCV) ja mootorikahjud</li>
            </ul>
            <p>
              Karterituulutus ehk PCV on üks alahinnatumaid süsteeme mootoris. Kui see ummistub või jääb hooldamata, tõuseb karteris rõhk, õli pressib tihenditest välja ja mootor hakkab “tossama”. Enamasti avastatakse see alles siis, kui leked on juba käes.
            </p>
          </header>

          <section>
            <Heading as="h2">Kuidas PCV-süsteem töötab ja miks see oluline on?</Heading>
            <p>
              PCV (Positive Crankcase Ventilation) juhib karterigaasid kontrollitult tagasi sisselaskesse, hoides <strong>rõhu tasakaalus ja õlikulu kontrolli all</strong>.
            </p>
            <ul>
              <li>normaalne karterirõhk;</li>
              <li>stabiilne tühikäik ja segu moodustumine;</li>
              <li>väiksem õlilekke ja õlikulu risk.</li>
            </ul>
          </section>

          <section>
            <Heading as="h2">Mis juhtub, kui karterituulutus ummistub?</Heading>
            <ul>
              <li><strong>Karterirõhk tõuseb:</strong> liigne rõhk pressib õli välja nõrgematest tihenditest – klapikambrikaan, karteri tihend, väntvõlli simmerid.</li>
              <li><strong>Tihendite lekked:</strong> algul väike niiskus, hiljem juba arvestatav õlileke.</li>
              <li><strong>Õli sisselaskes ja tossamine:</strong> õli jõuab põlemiskambrisse, suureneb õlikulu ja tekib sinakas suits.</li>
              <li><strong>Ebaühtlane töö:</strong> vale rõhk mõjutab segu, mootor võib hakata võdisema.</li>
            </ul>
          </section>

          <section>
            <Heading as="h2">Miks PCV-süsteemi peaaegu kunagi ei hooldata?</Heading>
            <p>
              PCV on peidus ja <strong>ükski “lihtsalt õlivahetus” seda ei kata</strong>. Tegelikkuses tasub ventiili, voolikuid ja kanaleid kontrollida iga <strong>80 000–120 000 km</strong> järel.
            </p>
          </section>

          <section>
            <Heading as="h2">Kahtlustad ummistunud karterituulutust?</Heading>
            <p>
              <a href="/kontakt">Võta ühendust Nisbeliga</a>, teeme mootorile sihtdiagnostika ja hindame PCV-süsteemi seisukorda.
            </p>
          </section>
        </article>
      </main>
    </div>
  );
}
